DROP TABLE IF EXISTS "public"."order_events";
-- Table Definition
CREATE TABLE "public"."order_events" (
    "id" uuid NOT NULL DEFAULT gen_random_uuid(),
    "order_id" uuid NOT NULL,
    "name" text NOT NULL,
    "payload" jsonb NOT NULL,
    "attempts" int4 NOT NULL DEFAULT 0,
    "next_retry_at" timestamp NOT NULL DEFAULT now(),
    "locked_at" timestamp,
    "locked_by" text,
    "processed_at" timestamp,
    "failed_at" timestamp,
    "dead_letter_at" timestamp,
    "error_message" text,
    "created_at" timestamp NOT NULL DEFAULT now(),
    PRIMARY KEY ("id")
);

DROP TABLE IF EXISTS "public"."order_types";
-- Table Definition
CREATE TABLE "public"."order_types" (
    "id" varchar(20) NOT NULL,
    "name" varchar(50) NOT NULL,
    PRIMARY KEY ("id")
);

DROP TABLE IF EXISTS "public"."orders";
DROP TYPE IF EXISTS "public"."order_status";
CREATE TYPE "public"."order_status" AS ENUM ('pending', 'confirmed', 'preparing', 'out_for_delivery', 'delivered', 'cancelled', 'order_ready');

-- Table Definition
CREATE TABLE "public"."orders" (
    "id" uuid NOT NULL DEFAULT gen_random_uuid(),
    "user_id" uuid NOT NULL,
    "restaurant_id" uuid NOT NULL,
    "status" "public"."order_status" NOT NULL DEFAULT 'pending'::order_status,
    "total" numeric(10,2) NOT NULL DEFAULT 0,
    "created_at" timestamp DEFAULT now(),
    "updated_at" timestamp DEFAULT now(),
    "confirmed_at" timestamp,
    "cancelled_at" timestamp,
    "delivery_address" text,
    "customer_name" varchar(255) NOT NULL DEFAULT ''::character varying,
    "customer_phone" varchar(30) NOT NULL DEFAULT ''::character varying,
    "payment_method" varchar(20) NOT NULL DEFAULT 'pix'::character varying CHECK ((payment_method)::text = ANY (ARRAY[('pix'::character varying)::text, ('dinheiro'::character varying)::text, ('debito'::character varying)::text, ('credito'::character varying)::text])),
    "notes" text,
    "delivery_fee" numeric(10,2) NOT NULL DEFAULT 8.00,
    "delivery_type" varchar(20) NOT NULL DEFAULT 'delivery'::character varying,
    "estimated_delivery_at" timestamp,
    "subtotal" numeric(10,2) NOT NULL DEFAULT 0,
    PRIMARY KEY ("id")
);

DROP TABLE IF EXISTS "public"."order_status_history";

-- Table Definition
CREATE TABLE "public"."order_status_history" (
    "id" uuid NOT NULL DEFAULT gen_random_uuid(),
    "order_id" uuid NOT NULL,
    "status" "public"."order_status" NOT NULL,
    "changed_at" timestamp DEFAULT now(),
    "changed_by" uuid,
    PRIMARY KEY ("id")
);

DROP TABLE IF EXISTS "public"."users";
-- Table Definition
CREATE TABLE "public"."users" (
    "id" uuid NOT NULL DEFAULT gen_random_uuid(),
    "name" text NOT NULL,
    "email" text NOT NULL,
    "password_hash" text NOT NULL,
    "role" text NOT NULL DEFAULT 'customer'::text,
    "created_at" timestamp DEFAULT now(),
    PRIMARY KEY ("id")
);

DROP TABLE IF EXISTS "public"."order_items";
-- Table Definition
CREATE TABLE "public"."order_items" (
    "id" uuid NOT NULL DEFAULT gen_random_uuid(),
    "order_id" uuid NOT NULL,
    "product_id" uuid NOT NULL,
    "quantity" int4 NOT NULL CHECK (quantity > 0),
    "unit_price" numeric(10,2) NOT NULL CHECK (unit_price >= (0)::numeric),
    "created_at" timestamp DEFAULT now(),
    PRIMARY KEY ("id")
);

DROP TABLE IF EXISTS "public"."products";
-- Table Definition
CREATE TABLE "public"."products" (
    "id" uuid NOT NULL DEFAULT gen_random_uuid(),
    "restaurant_id" uuid NOT NULL,
    "name" text NOT NULL,
    "price" numeric(10,2) NOT NULL CHECK (price >= (0)::numeric),
    "created_at" timestamp DEFAULT now(),
    "description" varchar(255),
    PRIMARY KEY ("id")
);

DROP TABLE IF EXISTS "public"."payment_methods";
